// ---------------------------------------------------------------------------
// Story 1 — NamingAxes
// ---------------------------------------------------------------------------
export const NamingAxes = {
  name: 'Naming axes',
  render: () => {
    const headerCells = SYSTEMS_ORDER.map(s =>
      `<th style="text-align:center;">${s}</th>`
    ).join('');

    const rows = NAMING_AXES.map(axis => {
      const cells = SYSTEMS_ORDER.map(sys => {
        const entry = axis.systems[sys];
        if (!entry || !entry.has) {
          return `<td style="text-align:center;"><span class="dash">—</span></td>`;
        }
        return `
          <td style="text-align:center;">
            <span class="check">✓</span>
            ${entry.example ? `<div style="font-size:9px;font-family:monospace;color:#777;margin-top:2px;line-height:1.3;">${entry.example}</div>` : ''}
            ${entry.note ? `<div style="font-size:9px;color:#aaa;font-style:italic;margin-top:2px;">${entry.note}</div>` : ''}
          </td>
        `;
      }).join('');

      return `
        <tr>
          <td style="min-width:180px;">
            <div style="font-size:12px;font-weight:700;color:${axis.color};">${axis.axis}</div>
            <div style="font-size:11px;color:#888;margin-top:2px;line-height:1.4;">${axis.description}</div>
          </td>
          ${cells}
        </tr>
      `;
    }).join('');

    const el = document.createElement('div');
    el.innerHTML = `
      <style>
        ${baseStyles}
        table { overflow-x: auto; display: block; }
        td, th { white-space: nowrap; min-width: 80px; }
        td:first-child { white-space: normal; min-width: 180px; }
      </style>
      <div class="page">
        <div class="page-title">Experimental / Nomenclature</div>
        <div class="page-subtitle">Naming axes</div>
        <div class="page-desc">
          A matrix showing which naming axes each system uses. Rows: naming axes.
          Columns: systems. The ✓ cells include an example token name where possible.
          This makes naming as an architectural decision visible across the benchmark.
        </div>
        <div style="overflow-x:auto;">
          <table>
            <thead>
              <tr>
                <th style="min-width:180px;">Naming axis</th>
                ${headerCells}
              </tr>
            </thead>
            <tbody>${rows}</tbody>
          </table>
        </div>

        <div style="background:#fff;border:1px solid #e0e0e0;border-radius:8px;padding:20px 24px;margin-top:8px;">
          <div style="font-size:13px;font-weight:700;color:#111;margin-bottom:12px;">Reading this matrix</div>
          <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px;">
            ${NAMING_AXES.map(a => `
              <div style="display:flex;gap:8px;align-items:flex-start;">
                <div style="width:10px;height:10px;border-radius:50%;background:${a.color};margin-top:3px;flex-shrink:0;"></div>
                <div>
                  <div style="font-size:12px;font-weight:700;color:${a.color};">${a.axis}</div>
                  <div style="font-size:11px;color:#777;">${a.description}</div>
                </div>
              </div>
            `).join('')}
          </div>
        </div>
      </div>
    `;
    return el;
  },
};

