export const TokenNameDissection = {
  name: 'Token name dissection',
  render: () => {
    const cards = DISSECTIONS.map(d => {
      const segments = d.segments.map(seg => {
        if (!seg.label) {
          return `<span style="font-size:24px;font-family:'SF Mono','Fira Code',monospace;color:${seg.color};font-weight:700;">${seg.text}</span>`;
        }
        return `
          <span style="display:inline-block;position:relative;margin-right:2px;">
            <span style="font-size:24px;font-family:'SF Mono','Fira Code',monospace;color:${seg.color};font-weight:700;
              border-bottom:2px solid ${seg.color};padding-bottom:1px;">${seg.text}</span>
            <span style="display:block;font-size:9px;color:${seg.color};text-align:center;
              font-weight:600;margin-top:6px;max-width:120px;line-height:1.3;white-space:nowrap;">${seg.label}</span>
          </span>
        `;
      }).join('');

      return `
        <div style="background:#fff;border-radius:10px;border:1px solid #e0e0e0;
          overflow:hidden;margin-bottom:24px;">
          <div style="padding:12px 20px;background:${d.color};display:flex;align-items:center;gap:10px;">
            <span style="font-size:12px;font-weight:700;color:#fff;letter-spacing:0.06em;text-transform:uppercase;">${d.system}</span>
          </div>
          <div style="padding:24px 20px 12px;">
            <div style="display:flex;flex-wrap:wrap;align-items:flex-start;gap:0;margin-bottom:40px;min-height:70px;">
              ${segments}
            </div>
            <div style="font-size:12px;color:#555;line-height:1.6;padding-top:12px;
              border-top:1px solid #f0f0f0;">
              ${d.note}
            </div>
          </div>
        </div>
      `;
    }).join('');

    const legend = [
      { label: 'Domain / namespace', color: '#888' },
      { label: 'Parameter type', color: '#0055bb' },
      { label: 'Speed / tier', color: '#c41c1c' },
      { label: 'Character / personality', color: '#7700cc' },
      { label: 'Direction / trajectory', color: '#007755' },
    ].map(l => `
      <div style="display:flex;align-items:center;gap:6px;margin-right:20px;">
        <div style="width:12px;height:3px;background:${l.color};border-radius:1px;"></div>
        <span style="font-size:11px;color:#555;">${l.label}</span>
      </div>
    `).join('');

    const el = document.createElement('div');
    el.innerHTML = `
      <style>${baseStyles}</style>
      <div class="page">
        <div class="page-title">Experimental / Nomenclature</div>
        <div class="page-subtitle">Token name dissection</div>
        <div class="page-desc">
          One token from each system, dissected segment by segment.
          Each segment is color-coded by what it communicates — domain, parameter type, speed tier,
          character, or direction. The dissection makes visible the architectural choice encoded in the name.
        </div>

        <div style="display:flex;flex-wrap:wrap;margin-bottom:40px;padding:16px 20px;
          background:#f5f5f5;border-radius:8px;">
          <div style="font-size:11px;font-weight:700;color:#888;text-transform:uppercase;
            letter-spacing:0.08em;width:100%;margin-bottom:10px;">Segment color key</div>
          ${legend}
        </div>

        ${cards}

        <div style="background:#f0f4ff;border-radius:8px;padding:20px 24px;margin-top:8px;">
          <div style="font-size:13px;font-weight:700;color:#111;margin-bottom:10px;">What naming reveals</div>
          <div style="font-size:13px;color:#555;line-height:1.6;">
            A token name is not just a label — it is an architectural commitment.
            eBay's four-segment name encodes character AND direction, making the token self-documenting
            at point of use. Polaris's literal name makes the value transparent but the name meaningless
            if the value changes. Uber's non-literal suffix adds abstraction but requires system familiarity.
            Carbon delegates all directional information to the function call, keeping token names clean.
            Each choice has trade-offs between transparency, stability, and expressiveness.
          </div>
        </div>
      </div>
    `;
    return el;
  },
};
